/**
 * Sidebar Component
 * Role-based navigation menu
 */

import React from 'react';

const Sidebar = ({ userRole, activePage, onPageChange }) => {
    // Admin navigation items
    const adminNavItems = [
        { id: 'dashboard', label: 'Dashboard', icon: '📊' },
        { id: 'departments', label: 'Departments', icon: '🏛️' },
        { id: 'teachers', label: 'Teachers', icon: '👨‍🏫' },
        { id: 'students', label: 'Students', icon: '👨‍🎓' },
        { id: 'rooms', label: 'Rooms', icon: '🚪' },
        { id: 'courses', label: 'Courses', icon: '📚' },
        { id: 'approvals', label: 'Approval Queue', icon: '⏳' },
    ];

    // Student navigation items
    const studentNavItems = [
        { id: 'timetable', label: 'My Timetable', icon: '📅' },
        { id: 'find-class', label: 'Find My Class', icon: '📍' },
    ];

    // Teacher navigation items
    const teacherNavItems = [
        { id: 'class-locator', label: 'Class Locator', icon: '📍' },
        { id: 'my-schedule', label: 'My Schedule', icon: '📅' },
    ];

    const getNavItems = () => {
        switch (userRole) {
            case 'admin': return adminNavItems;
            case 'student': return studentNavItems;
            case 'teacher': return teacherNavItems;
            default: return adminNavItems;
        }
    };

    const getUserName = () => {
        switch (userRole) {
            case 'admin': return 'Admin User';
            case 'student': return 'Student User';
            case 'teacher': return 'Teacher User';
            default: return 'User';
        }
    };

    const getUserEmail = () => {
        switch (userRole) {
            case 'admin': return 'admin@scras.edu';
            case 'student': return 'student@scras.edu';
            case 'teacher': return 'teacher@scras.edu';
            default: return 'user@scras.edu';
        }
    };

    const navItems = getNavItems();

    return (
        <div className="sidebar">
            <div className="sidebar-header">
                <h2>SCRAS</h2>
                <span className="role-badge">{userRole}</span>
            </div>

            <nav className="sidebar-nav">
                {navItems.map(item => (
                    <button
                        key={item.id}
                        className={`nav-item ${activePage === item.id ? 'active' : ''}`}
                        onClick={() => onPageChange(item.id)}
                    >
                        <span className="nav-icon">{item.icon}</span>
                        <span>{item.label}</span>
                    </button>
                ))}
            </nav>

            <div className="sidebar-footer">
                <div className="user-info">
                    <span className="user-name">{getUserName()}</span>
                    <span className="user-email">{getUserEmail()}</span>
                </div>
            </div>
        </div>
    );
};

export default Sidebar;
